mapper.update:
UPDATE sys_role
role_name = #{roleName}, description = #{description}, status = #{status}, menu_permissions = #{menuPermissions}, operation_permissions = #{operationPermissions}, gremlin_permission = #{gremlinPermission}, dangerous_permissions = #{dangerousPermissions}, connection_default = #{connectionDefault}, update_time = CURRENT_TIMESTAMP
WHERE id = #{id}

UPDATE sys_user
SET roles = CASE
    WHEN roles IS NULL OR roles = '' THEN #{roleKey}
    WHEN string_to_array(roles, ',') @> ARRAY[#{roleKey}]::text[] THEN roles
    ELSE roles || ',' || #{roleKey}
END,
update_time = CURRENT_TIMESTAMP
WHERE id = #{userId}

UPDATE sys_user
SET roles = (
    SELECT string_agg(r, ',') FROM (
        SELECT trim(part) AS r
        FROM unnest(string_to_array(COALESCE(roles, ''), ',')) AS part
        WHERE trim(part) != #{roleKey} AND trim(part) != ''
    ) t
),
update_time = CURRENT_TIMESTAMP
WHERE id = #{userId}

