INSERT INTO sys_role_connection_auth (role_id, connection_id, access_level)
VALUES (#{roleId}, #{connectionId}, #{accessLevel})
ON CONFLICT (role_id, connection_id) DO UPDATE SET access_level = #{accessLevel}
